var e=[{id:`L2_1`,type:`dialog`,speaker:null,text:{KOREA:`오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.`,JPN:`長い間悩んだ結果、あなたは一つ大事なことに気づいた。`,ENG:`After much debate, you came to the conclusion`,TWN:`苦惱許久後，你意識到一件重要的事實。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L3_1`,type:`dialog`,speaker:null,text:{KOREA:`줄곧 생각해 온 그야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.`,JPN:`ずっと考えてきた彼だからこそ、これから向き合う運命に必ず必要な存在であることを。`,ENG:`that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.`,TWN:`經過長久的思考，你明白在今後即將面對的命運中，他是必不可少的存在。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L4_1`,type:`dialog`,speaker:null,text:{KOREA:`그리하여 당신은 결심했다.`,JPN:`そして、あなたは決心した。`,ENG:`So, you've decided`,TWN:`所以你下定決心。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L5_1`,type:`dialog`,speaker:null,text:{KOREA:`이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그와 함께하기로.`,JPN:`この世界でどのような結末を迎えるとしても、最後まで彼とともにいることを。`,ENG:`that you'll be with him, no matter the consequences.`,TWN:`不管這個世界會迎來怎樣的結局，你都要和他一起走到最後。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L6_1`,type:`dialog`,speaker:null,text:{KOREA:`마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.`,JPN:`意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。`,ENG:`Having decided that, you called him to your office. He said he'd be here soon.`,TWN:`做好心理準備後，你將他傳喚到老闆辦公室，他說馬上就會過來。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L12_1`,type:`dialog`,speaker:`LEE_FRONTIER_NULL_NULL`,text:{KOREA:`하아......`,JPN:`ふう……`,ENG:`*Sigh*`,TWN:`哈啊……`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`LEE_FRONTIER_NULL_NULL`,face:`UNIT_DESPAIR`},R:null}}},{id:`L13_1`,type:`dialog`,speaker:`LEE_FRONTIER_NULL_NULL`,text:{KOREA:`나도 시원시원한 걸 좋아하긴 하는데, 이렇게 불쑥 들이밀면 좀 당황스럽다고.`,JPN:`俺もはっきり言ってくれるほうがいいけど、
こんなに突然突きつけられても困るんだよな。`,ENG:`I don't like beating around the bush either, but even to me, this is a bit of a surprise.`,TWN:`雖然我喜歡做事爽快點，但你這樣突然把契約推到我面前，不管是誰都會被嚇到的。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`LEE_FRONTIER_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L14_1`,type:`dialog`,speaker:`LEE_FRONTIER_NULL_NULL`,text:{KOREA:`그래, 종신 계약인가......`,JPN:`そうか、終身契約か……`,ENG:`So, a lifetime contract, huh?`,TWN:`是嗎，終身契約……`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`LEE_FRONTIER_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L15_1`,type:`dialog`,speaker:`LEE_FRONTIER_NULL_NULL`,text:{KOREA:`길바닥 인생한테 감정가를 너무 후하게 쳐 주는 거 아냐?`,JPN:`一文無しの俺にとっては身に余る待遇だと思わないか？`,ENG:`Are you sure you want to bet on a lowlife like me?`,TWN:`對我這種下流人生，你給我的的鑑定價會不會太高了？`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`LEE_FRONTIER_NULL_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L16_1`,type:`dialog`,speaker:`LEE_FRONTIER_NULL_NULL`,text:{KOREA:`하긴, 뭐......`,JPN:`まぁ、でも……`,ENG:`Well...`,TWN:`不過，這個嘛……`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`LEE_FRONTIER_NULL_NULL`,face:`UNIT_LAUGH`},R:null}}},{id:`L17_1`,type:`dialog`,speaker:`LEE_FRONTIER_NULL_NULL`,text:{KOREA:`이렇게까지 믿어 주는데, 뒤로 빼는 건 내 성격에 안 맞지.`,JPN:`ここまで信じてくれてるのに、遠慮するのは性に合わないんだ。`,ENG:`If you trust me so much, then I'll have to repay you in kind.`,TWN:`你都這麼信任我了，這種時候退縮可不符合我的性格。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`LEE_FRONTIER_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L18_1`,type:`dialog`,speaker:`LEE_FRONTIER_NULL_NULL`,text:{KOREA:`좋아. 네 선택이 틀리지 않았다는 걸, 이 주먹으로 증명해 주면 되는 거네.`,JPN:`いいぞ。社長の選択が間違ってなかったことを、この拳で証明してやるさ。`,ENG:`Alright, I'll prove to you with my fists that you've made the right decision.`,TWN:`好，我就用這雙拳頭來證明你的選擇並沒有錯吧。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`LEE_FRONTIER_NULL_NULL`,face:`UNIT_PRIDE`},R:null}}}];export{e as default};